import torch
import torch.nn as nn
from torch.autograd import Function
from torch.cuda.amp import custom_fwd, custom_bwd

class FusedMatMul(Function):
    @staticmethod
    @custom_fwd(cast_inputs=torch.float32)
    def forward(ctx, A, B, bias=None, relu=False, scale=None, clamp_min=None, clamp_max=None):
        ctx.save_for_backward(A, B, bias)
        C = torch.matmul(A, B)
        if bias is not None:
            C += bias
        if relu:
            C = torch.relu(C)
        if scale is not None:
            C *= scale
        if clamp_min is not None or clamp_max is not None:
            C = torch.clamp(C, min=clamp_min, max=clamp_max)
        return C

    @staticmethod
    @custom_bwd
    def backward(ctx, grad_output):
        A, B, bias = ctx.saved_tensors
        grad_A = torch.matmul(grad_output, B.t())
        grad_B = torch.matmul(A.t(), grad_output)
        grad_bias = None
        if bias is not None:
            grad_bias = torch.sum(grad_output, dim=0)
        return grad_A, grad_B, grad_bias, None, None, None, None

class ModelNew(nn.Module):
    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        return FusedMatMul.apply(A, B, None, False, None, None, None)

