from torch.cuda.amp import custom_fwd, custom_bwd

class MmaOpFunction(Function):
    @staticmethod
    @custom_fwd(cast_inputs=torch.float32)
    def forward(ctx, A, B):
        C = torch.matmul(A, B)
        ctx.save_for_backward(A, B, C)
        return C

    @staticmethod
    @custom_bwd
    def backward(ctx, dC):
        A, B, C = ctx.saved_tensors
        dA = torch.matmul(dC, B.transpose(0, 1))
        dB = torch.matmul(A.transpose(0, 1), dC)
        return dA, dB

class ModelNew(nn.Module):
    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        return MmaOpFunction.apply(A, B)

